class YieldWithDelayTest : TestBase() {

    /**
     * Tests that yield() gives priority to a coroutine that was launched with UNDISPATCHED
     * and whose delay has already expired.
     *
     * The sequence should be:
     * 1. launch starts immediately (UNDISPATCHED)
     * 2. delay(1) suspends the launched coroutine
     * 3. Thread.sleep(100) passes enough time for the delay to expire
     * 4. yield() should give priority to the delayed task that is now ready
     * 5. "first" should print before "second"
     */
    @Test
    fun testYieldGivesPriorityToExpiredDelay() = runTest {
        val result = mutableListOf<String>()

        launch(start = CoroutineStart.UNDISPATCHED) {
            delay(1)
            result.add("first")
        }

        // Wait long enough for the delay to expire
        // Using delay with a longer time instead of Thread.sleep for platform compatibility
        delay(100)

        yield()
        result.add("second")

        // Let any remaining tasks complete
        yield()

        assertEquals(listOf("first", "second"), result, 
            "yield() should give priority to the coroutine whose delay has expired")
    }

    /**
     * Similar test but with multiple delayed coroutines
     */
    @Test
    fun testYieldGivesPriorityToMultipleExpiredDelays() = runTest {
        val result = mutableListOf<String>()

        launch(start = CoroutineStart.UNDISPATCHED) {
            delay(1)
            result.add("first")
        }

        launch(start = CoroutineStart.UNDISPATCHED) {
            delay(2)
            result.add("second")
        }

        // Wait long enough for both delays to expire
        delay(100)

        yield()
        result.add("third")

        // Let any remaining tasks complete
        yield()
        yield()

        assertEquals(listOf("first", "second", "third"), result,
            "yield() should give priority to coroutines whose delays have expired")
    }

    /**
     * Test that a non-expired delay is NOT given priority over yield
     */
    @Test
    fun testYieldDoesNotWaitForUnexpiredDelay() = runTest {
        val result = mutableListOf<String>()

        launch(start = CoroutineStart.UNDISPATCHED) {
            delay(10000) // Very long delay that won't expire during test
            result.add("delayed")
        }

        yield()
        result.add("immediate")

        // The delayed coroutine should not have run yet
        assertEquals(listOf("immediate"), result,
            "yield() should not wait for unexpired delays")
    }
}
